/**
 * Map of domain names to platform names
 */
const DOMAIN_TO_PLATFORM: Record<string, keyof typeof PLATFORM_ICONS> = {
    'agoda.com': 'AGODA',
    'trip.com': 'TRIP_COM',
    'booking.com': 'BOOKING_COM',
    'viator.com': 'VIATOR',
    'headout.com': 'HEADOUT',
    'getyourguide.com': 'GETYOURGUIDE',
    'getyourguide.co.uk': 'GETYOURGUIDE',
    'klook.com': 'KLOOK',
    'expedia.com': 'EXPEDIA',
    'cleartrip.com': 'CLEARTIP',
    'makemytrip.com': 'MAKE_MY_TRIP',
    'goibibo.com': 'GOIBIBO',
    'visa2fly.com': 'VISA2FLY',
    'teleport.org': 'TELEPORT',
    'teleport.com': 'TELEPORT',
    'useteleport.com': 'TELEPORT',
    'kayak.com': 'KAYAK'
}

/**
 * Extract platform name from URL to match with platform icons
 * Handles subdomains like rimigo.useteleport.com and rimigo.visa2fly.com
 * @param url - The URL to extract platform name from
 * @returns Platform name in uppercase (e.g., 'AGODA', 'BOOKING_COM') or null if not found
 */
export const extractPlatformNameFromUrl = (url: string): string | null => {
    try {
        const urlObj = new URL(url)
        const hostname = urlObj.hostname.toLowerCase().replace('www.', '')
        
        // Check exact match first
        if (DOMAIN_TO_PLATFORM[hostname]) {
            return DOMAIN_TO_PLATFORM[hostname]
        }
        
        // Handle subdomains: extract root domain
        // e.g., rimigo.useteleport.com -> useteleport.com
        // e.g., rimigo.visa2fly.com -> visa2fly.com
        const hostnameParts = hostname.split('.')
        if (hostnameParts.length > 2) {
            // Has subdomain, try to match with root domain
            // Get last 2 parts (e.g., "useteleport.com" from "rimigo.useteleport.com")
            const rootDomain = hostnameParts.slice(-2).join('.')
            if (DOMAIN_TO_PLATFORM[rootDomain]) {
                return DOMAIN_TO_PLATFORM[rootDomain]
            }
            
            // Also try matching with the full domain including subdomain
            // Check if hostname ends with any known domain
            for (const [domain, platform] of Object.entries(DOMAIN_TO_PLATFORM)) {
                if (hostname.endsWith(`.${domain}`) || hostname === domain) {
                    return platform
                }
            }
            
            // For special cases, check if any part contains a platform's base domain
            // e.g., "useteleport" contains "teleport"
            for (const [domain, platform] of Object.entries(DOMAIN_TO_PLATFORM)) {
                const baseDomain = domain.split('.')[0] // e.g., "teleport" from "teleport.com"
                // Check if any part of hostname contains the base domain
                if (hostnameParts.some(part => part.includes(baseDomain))) {
                    return platform
                }
            }
        }
        
        // For domains without subdomains, check if hostname ends with any known domain
        for (const [domain, platform] of Object.entries(DOMAIN_TO_PLATFORM)) {
            if (hostname.endsWith(`.${domain}`) || hostname === domain) {
                return platform
            }
        }
        
        // Check if hostname contains any platform's base domain name
        for (const [domain, platform] of Object.entries(DOMAIN_TO_PLATFORM)) {
            const baseDomain = domain.split('.')[0]
            if (hostname.includes(baseDomain)) {
                return platform
            }
        }
        
        // Extract base domain name (e.g., "agoda" from "agoda.com")
        const baseDomain = hostname.split('.')[0]
        return baseDomain ? baseDomain.toUpperCase() : null
    } catch {
        return null
    }
}

export const getPlatformLogoURL = (platform: string | null | undefined): string | null => {
    if (!platform) return null
    return PLATFORM_ICONS[platform.toUpperCase() as keyof typeof PLATFORM_ICONS] ?? null
}
